"""# 3.Collection Management


**Define Collection Name:**
We start by defining a constant, COLLECTION_NAME, which will be used as the identifier for our collection in AstraDB. In this example, the collection is named "multilingual_search".

**Check for Existing Collections:**

-Listing Collections:
We call database.list_collections() to retrieve a list of all existing collections in the specified keyspace.

-Dimension Validation:
We iterate over each collection (coll) and check two conditions:
Name Match: If the collection's name matches COLLECTION_NAME.

-Dimension Mismatch: If the collection's vector dimension (stored in coll.options.vector.dimension) does not equal our expected VECTOR_DIMENSION (which was determined when we encoded a sample text).

-Dropping Mismatched Collection:
If both conditions are met, it indicates that an existing collection has been set up with an incorrect vector dimension. We then drop that collection using database.drop_collection(COLLECTION_NAME) to avoid issues later during vector search operations.
"""


def create_collection_simple(database, collection_name, vector_dimension=1472):
    """
    Simple collection creation with basic validation.
    """
    try:
        # Check if collection exists
        existing_collections = database.list_collections()
        collection_exists = any(coll.name == collection_name for coll in existing_collections)

        if collection_exists:
            print(f"Collection '{collection_name}' already exists")
            return database.get_collection(collection_name)

        # Create new collection
        collection = database.create_collection(
            name=collection_name,
            options={"vector": {"dimension": vector_dimension, "metric": VectorMetric.COSINE}},
        )
        print(f"Created collection '{collection_name}'")
        return collection

    except Exception as e:
        print(f"Error creating collection: {e}")
        raise


# Usage
collection = create_collection_simple(database, "multilingual_search", 1472)


def create_collection_simple(database, collection_name, vector_dimension=1472):
    """
    Simple collection creation with basic validation.
    """
    # Check if collection exists
    existing_collections = database.list_collections()
    collection_exists = any(coll.name == collection_name for coll in existing_collections)
    if collection_exists:
        print(f"Collection '{collection_name}' already exists")
        return database.get_collection(collection_name)
    # Create new collection
    # Create a collection
    collection_definition = CollectionDefinition(
        vector=CollectionVectorOptions(
            dimension=vector_dimension,
            metric=VectorMetric.COSINE,
        ),
    )
    collection = database.create_collection(
        collection_name,
        definition=collection_definition,
    )
    print(f"Created collection '{collection_name}'")
    return collection


# Usage
collection = create_collection_simple(database, "multilingual_search", 1472)

"""# 4. Insert sample data with vector validation

**Defining Sample Documents:**

We create a list called documents that contains three dictionaries.

Each dictionary represents a sample profile with the following attributes:
    - name: The person's name.
    - text: A description of the person's professional role, including location.
    - country: The country associated with the document.

Generating Embeddings:

For each document, we concatenate the name and text fields to form a single string.
This string is then passed to the encode() function, which transforms the text into a 1472-dimensional vector.
The resulting vector (stored in the variable embedding) captures the semantic meaning of the document's combined content.

**Inserting Documents into AstraDB:**

We use collection.insert_one() to insert each document into our AstraDB collection.

The original document data is expanded into the new dictionary using **doc.
We add a special key, "$vector", which stores the generated embedding. This vector is crucial for enabling vector search operations later.

A unique _id is created for each document by combining the country with a normalized version of the name (converted to lowercase and with spaces replaced by underscores). This unique identifier ensures that each document is distinct within the collection.

**Purpose**
 - Sample Data for Testing:
The inserted sample documents provide test data for demonstrating how vector search works in AstraDB.

 - Vector Validation:
By generating and storing the vector embedding for each document, we validate that our encoding process produces the correct vector format and dimension (1472), which is essential for the subsequent vector search functionality.

 -Unique Identification:
The custom _id ensures that each document is uniquely identifiable within the collection, which is important for data management and retrieval operations in AstraDB.
"""

# 4. Insert (or upsert) sample data with vector validation using
# update_one without modifying _id

# Define a list of documents, each containing a name, descriptive text,
# and country.
documents = [
    {"name": "Jóhann Müller", "text": "Software developer from Berlin", "country": "Germany"},
    {"name": "Jean Dupont", "text": "Développeur de logiciels à Paris", "country": "France"},
    {"name": "Giovanni Rossi", "text": "Sviluppatore software di Milano", "country": "Italy"},
]

# Iterate over each document.
for doc in documents:
    # Compute the vector embedding from the combined name and text.
    embedding = encode(f"{doc['name']} {doc['text']}")

    # Create a unique _id based on country and normalized name.
    unique_id = f"{doc['country']}_{doc['name'].lower().replace(' ', '_')}"

    # Build the new document including the _id.
    new_doc = {
        **doc,  # Original document data.
        "$vector": embedding,  # The computed vector.
        "_id": unique_id,  # Unique identifier.
    }

    # Check if a document with this _id already exists.
    existing_doc = collection.find_one({"_id": unique_id})
    if existing_doc:
        # Document exists: prepare an update document without _id.
        update_doc = new_doc.copy()
        update_doc.pop("_id", None)  # Remove _id from update data.
        collection.update_one({"_id": unique_id}, {"$set": update_doc})
        print(f"Updated document with _id: {unique_id}")
    else:
        # Document does not exist: insert it.
        collection.insert_one(new_doc)
        print(f"Inserted document with _id: {unique_id}")

"""# 5. Define a safe search function for vector search with cosine similarity conversion

**Purpose of the Function:**

The safe_search function is designed to perform a vector search on our AstraDB collection.
It takes a query string and an optional country_filter to narrow down the search results.
The function returns a list of documents, each containing a raw cosine distance (a measure of similarity), which can later be converted into a cosine similarity score.

**Encoding the Query:**

The function begins by encoding the query text using the encode function. This converts the query into a high-dimensional vector representation (embedding) that captures its semantic meaning.

**Filtering by Country:**

If a country_filter is provided, a dictionary is created to filter results to documents that match the specified country.
If no country filter is provided, an empty filter ({}) is used, meaning no country-based filtering is applied.

**Performing the Vector Search:**

The collection.find() method is called with the following parameters:
filter: Applies the country filter if provided.
sort: Uses the special key "$vector": embedding to sort the documents by their cosine distance to the query vector.

The cosine distance is a measure where 0.0 indicates a perfect match (i.e., the vectors are identical) and higher values indicate less similarity.
limit: Restricts the number of results returned to the top 3 closest matches.

**Error Handling:**

The entire search operation is wrapped in a try/except block. If an error occurs during the search (for example, due to connectivity issues or misconfiguration), the function catches the exception, prints an error message, and returns an empty list. This ensures that the search function fails gracefully.

**Conversion of Cosine Distance to Similarity:**

Although not done inside this function, the raw cosine distance (returned in each document as $similarity) can later be converted to cosine similarity by computing 1 - distance. This conversion is useful because a cosine similarity score of 1.0 indicates a perfect match.

Overall, this function encapsulates the vector search process in a robust and fault-tolerant manner, enabling us to query our dataset effectively while optionally filtering by country and handling errors gracefully.
"""


# 5. Define a safe search function for vector search with cosine
# similarity conversion
def safe_search(query, country_filter=None):
    """
    Performs a vector search on the collection using the encoded query.
    Optionally filters results by country.

    Returns a list of documents with the raw cosine distance, which will be converted to similarity.
    """
    try:
        # Encode the input query text into a vector using our previously defined `encode` function.
        # This vector represents the semantic meaning of the query.
        embedding = encode(query)

        # If a country filter is provided, construct a filter dictionary to restrict results to that country.
        # Otherwise, use an empty dictionary to apply no filtering.
        search_filter = {"country": country_filter} if country_filter else {}

        # Perform a vector search on the collection:
        # - 'filter' applies the country filter if one is provided.
        # - 'sort' uses the '$vector' key to sort documents based on their cosine distance from the query's vector.
        #   Note: The vector search returns the raw cosine distance (where 0.0 means a perfect match).
        # - 'limit' restricts the number of returned results to 3.
        results = collection.find(filter=search_filter, sort={"$vector": embedding}, limit=3)

        # Convert the results (cursor) to a list and return them.
        return list(results)

    except Exception as e:
        # If any error occurs during the search, print an error message and
        # return an empty list.
        print(f"Search error: {str(e)}")
        return []


