# --- Advanced Query Examples Using Wildcards, LIKE Patterns, and % Wildcards ---

# In these examples, we simulate advanced query patterns where users may use wildcards
# ('*' and '%') similar to SQL's LIKE operator. Since the Data API doesn't support full
# SQL-like regex filtering, we build regex patterns from the user's query and perform
# client-side filtering on the results. The following functions and
# examples illustrate this.


# -------------------------------------------------------------------------------
# Function: build_regex_pattern
# -------------------------------------------------------------------------------
# Purpose:
#   This function converts a query pattern containing '*' or '%' wildcards into a valid
#   regular expression pattern. The process is as follows:
#     1. Replace all '*' and '%' in the query with a temporary placeholder.
#     2. Escape the entire string to neutralize any regex-special characters.
#     3. Replace the placeholder with '.*' to simulate the SQL LIKE operator, where '.*'
#        matches any sequence of characters.
def build_regex_pattern(query_pattern):
    # Use a placeholder that is unlikely to occur in the text.
    placeholder = "__WILDCARD__"
    # Replace '*' and '%' with the placeholder.
    temp_pattern = query_pattern.replace("*", placeholder).replace("%", placeholder)
    # Escape the pattern so that all regex special characters are neutralized.
    escaped = re.escape(temp_pattern)
    # Replace the placeholder with '.*' to allow flexible matching.
    regex_pattern = escaped.replace(placeholder, ".*")
    return regex_pattern


# -------------------------------------------------------------------------------
# Function: filter_results_with_regex
# -------------------------------------------------------------------------------
# Purpose:
#   This function filters a list of documents (results) by applying a compiled regex pattern
# to a specific field's value. It returns only those documents where the
# regex finds a match.
def filter_results_with_regex(results, field, regex_pattern):
    compiled = re.compile(regex_pattern, re.IGNORECASE)
    return [doc for doc in results if compiled.search(doc.get(field, ""))]


# -------------------------------------------------------------------------------
# Example 1: Using '*' Wildcard
# -------------------------------------------------------------------------------
# Purpose:
#   This example demonstrates how to handle a query that uses the '*' wildcard.
#   For instance, the query "Senior * Developer" should match any job title that starts
#   with "Senior", followed by any characters, and then "Developer".
wildcard_query1 = "Senior * Developer"
# Convert the wildcard query into a regex pattern.
regex_pattern1 = build_regex_pattern(wildcard_query1)
print(f"Query with wildcard: '{wildcard_query1}' converted to regex: '{regex_pattern1}'")

# Retrieve candidate documents from the collection (filtered by location "Berlin").
# The sort parameter uses the encoded vector of the query "Senior Software Developer in Berlin"
# to rank documents by similarity.
results1 = collection_dse.find(
    filter={"location": "Berlin"},
    sort={"$vector": encode("Senior Software Developer in Berlin")},
    limit=10,
)
results1 = list(results1)
# Apply client-side regex filtering on the "job_title" field using the
# generated regex.
filtered_results1 = filter_results_with_regex(results1, "job_title", regex_pattern1)

print("\nResults for Query 1 (using * wildcard) after client-side regex filtering:")
# Iterate over the top three filtered results, convert the raw cosine distance to cosine similarity,
# and print the candidate's name and job title along with the similarity score.
for doc in filtered_results1[:3]:
    distance = doc.get("$similarity", 0)
    similarity = 1 - distance  # Convert cosine distance to cosine similarity.
    print(f"  - {doc['name']} | {doc['job_title']} (Cosine Similarity: {similarity:.2f})")


# -------------------------------------------------------------------------------
# Example 2: Using '%' Wildcard
# -------------------------------------------------------------------------------
# Purpose:
#   This example shows how to process a query that uses the '%' wildcard.
#   For example, "Senior % Developer" is converted into a regex pattern that should
#   behave similarly to the '*' wildcard case.
wildcard_query2 = "Senior % Developer"
# Convert the query into a regex pattern.
regex_pattern2 = build_regex_pattern(wildcard_query2)
print(f"\nQuery with wildcard: '{wildcard_query2}' converted to regex: '{regex_pattern2}'")

# Retrieve candidate documents (again, filtered by location "Berlin") and
# sorted by vector similarity.
results2 = collection_dse.find(
    filter={"location": "Berlin"},
    sort={"$vector": encode("Senior Software Developer in Berlin")},
    limit=10,
)
results2 = list(results2)
# Filter the results on the "job_title" field using the generated regex.
filtered_results2 = filter_results_with_regex(results2, "job_title", regex_pattern2)

print("\nResults for Query 2 (using % wildcard) after client-side regex filtering:")
for doc in filtered_results2[:3]:
    distance = doc.get("$similarity", 0)
    similarity = 1 - distance
    print(f"  - {doc['name']} | {doc['job_title']} (Cosine Similarity: {similarity:.2f})")


# -------------------------------------------------------------------------------
# Example 3: Using Double '%' Wildcards (%%)
# -------------------------------------------------------------------------------
# Purpose:
#   This example demonstrates the use of double '%' wildcards, a pattern often used in SQL
#   to match any substring containing a particular sequence. For example, "%%Developer%%"
#   should match any job title that contains "Developer" anywhere.
wildcard_query3 = "%%Developer%%"
# Convert the double '%' query into a regex pattern.
regex_pattern3 = build_regex_pattern(wildcard_query3)
print(f"\nQuery with wildcard: '{wildcard_query3}' converted to regex: '{regex_pattern3}'")

# Retrieve candidate documents from the collection, filtering by location "Berlin"
# and sorting by vector similarity using the query "Software Developer".
