# Apply client-side regex filtering on the "job_title" field.
filtered_results3 = filter_results_with_regex(results3, "job_title", regex_pattern3)

print("\nResults for Query 3 (using %% wildcards) after client-side regex filtering:")
for doc in filtered_results3[:3]:
    distance = doc.get("$similarity", 0)
    similarity = 1 - distance
    print(f"  - {doc['name']} | {doc['job_title']} (Cosine Similarity: {similarity:.2f})")

print("=== Advanced Query Examples Using Explicit LIKE Operator ===")


# -------------------------------------------------------------------------------
# Function: build_regex_pattern
# -------------------------------------------------------------------------------
# Purpose:
#   This function converts a query pattern containing '*' or '%' wildcards into a regex pattern.
#   The process involves:
#     1. Escaping the entire query pattern to neutralize regex special characters.
#     2. Replacing escaped '*' with '.*' so that it matches any sequence of characters.
#     3. Replacing literal '%' characters with '.*' as well.
#   This transformation simulates the behavior of the SQL LIKE operator.
def build_regex_pattern(query_pattern):
    # Escape the query pattern to neutralize regex-special characters.
    escaped = re.escape(query_pattern)
    print(f"DEBUG: Escaped pattern for '{query_pattern}' is '{escaped}'")
    # Replace escaped '*' (i.e., "\*") with ".*"
    regex_pattern = escaped.replace(r"\*", ".*")
    # Replace literal '%' characters with ".*"
    regex_pattern = regex_pattern.replace("%", ".*")
    print(f"DEBUG: Regex pattern after conversion is '{regex_pattern}'")
    return regex_pattern


# -------------------------------------------------------------------------------
# Function: parse_explicit_like
# -------------------------------------------------------------------------------
# Purpose:
#   This function parses a query that uses an explicit LIKE operator.
#   For example, given a query like:
#       "job_title LIKE '%Developer%'"
#   It extracts:
#       - The field name ("job_title")
#       - The like pattern ("%Developer%")
#   Then it converts the like pattern to a regex using the build_regex_pattern function.
# It returns a tuple (field, regex_pattern) if a match is found, otherwise
# (None, None).
def parse_explicit_like(query):
    # Define a pattern to capture a field, the LIKE keyword, and a pattern in
    # single quotes.
    pattern = r"(\w+)\s+LIKE\s+'(.+)'"
    match = re.search(pattern, query, re.IGNORECASE)
    if match:
        field = match.group(1)
        like_pattern = match.group(2)
        # Convert the like pattern into a regex.
        regex = build_regex_pattern(like_pattern)
        return field, regex
    return None, None


# -------------------------------------------------------------------------------
# Example: Explicit LIKE Operator Query
# -------------------------------------------------------------------------------
# Purpose:
#   This example demonstrates processing a query that explicitly uses the LIKE operator.
#   The query "job_title LIKE '%Developer%'" indicates that we want to match documents
#   where the 'job_title' field contains the substring "Developer".
explicit_like_query = "job_title LIKE '%Developer%'"
# Parse the explicit LIKE query to extract the field and convert the pattern.
field, regex_pattern = parse_explicit_like(explicit_like_query)
print(f"\nExplicit LIKE Query: '{explicit_like_query}'")
print(f"Parsed Field: '{field}', Regex Pattern: '{regex_pattern}'")

# -------------------------------------------------------------------------------
# Retrieve Candidate Documents from AstraDB
# -------------------------------------------------------------------------------
# Purpose:
#   Retrieve a broader set of candidate documents from the collection (collection_dse)
#   using a basic filter. Here, we filter by location "Berlin" and sort by vector similarity
#   using the encoded query "Software Developer". We retrieve more results than needed to
#   allow client-side regex filtering.
results_like = collection_dse.find(
    filter={"location": "Berlin"},  # Basic filter on location.
    sort={"$vector": encode("Software Developer")},
    # Sort by vector similarity.
    limit=10,  # Retrieve a larger set of documents for filtering.
)
results_like = list(results_like)

# -------------------------------------------------------------------------------
# Apply Client-Side Regex Filtering Based on the Explicit LIKE Query
# -------------------------------------------------------------------------------
# Purpose:
#   Use the regex pattern obtained from parsing the explicit LIKE query to filter the candidate
# documents. The filtering is applied on the field extracted from the
# explicit LIKE query (e.g., "job_title").
if field and regex_pattern:
    filtered_results_like = [
        doc for doc in results_like if re.search(regex_pattern, doc.get(field, ""), re.IGNORECASE)
    ]
else:
    filtered_results_like = results_like

# -------------------------------------------------------------------------------
# Display the Filtered Results
# -------------------------------------------------------------------------------
# Purpose:
#   Print out the documents that match the explicit LIKE query after client-side filtering.
#   Each document (row) is printed in full to show that it meets the criteria.
print("\nResults for Explicit LIKE Query after client-side regex filtering:")
for doc in filtered_results_like:
    print(doc)

