def create_index_if_not_exists(session, table_name, column_name, index_name):
    """
    Create an index only if it doesn't already exist
    """
    try:
        # Check if index already exists
        check_index_query = """
        SELECT index_name FROM system_schema.indexes
        WHERE keyspace_name = 'default_keyspace'
        AND table_name = '{table_name}'
        AND index_name = '{index_name}'
        """
        result = session.execute(check_index_query)

        if not result:
            # Index doesn't exist, create it
            create_index_query = """
            CREATE CUSTOM INDEX IF NOT EXISTS {index_name}
            ON default_keyspace.{table_name} ({column_name})
            USING 'StorageAttachedIndex'
            """
            session.execute(create_index_query)
            print(f"Created index: {index_name}")
        else:
            print(f"Index {index_name} already exists, skipping...")

    except Exception as e:
        print(f"Error with index {index_name}: {e}")


