results = search_by_vector_complex(
    "Software developer in Europe", filters={"country": "Germany", "name": "Jóhann Müller"}, limit=5
)
for row in results:
    print(f"  => {row.name}, desc='{row.description}', country={row.country}, sim={row.sim:.3f}")

"""# Inserting Documents with Prepared CQL and LOCAL_QUORUM Consistency

**CQL Insert Statement Preparation:**

The insert statement is defined with placeholders (?) for each column value. The statement is prepared with session.prepare(insert_cql), which compiles it for reuse. Setting the write consistency level to LOCAL_QUORUM ensures that the write operation is acknowledged by a majority of the local replicas in Astra DB, which improves data reliability.

**Sample Data Definition:**

The documents list contains several dictionaries, each representing a document with a name, description, and country. This sample data simulates real-world records for ingestion.

**Document Insertion Process:**
For each document:

-- A unique identifier (uid) is generated using Python’s uuid.uuid4().
-- The name, description, and country fields are concatenated into a single string (text_for_encoding), which is then encoded into a vector embedding using the encode() function.
-- The prepared insert statement is executed with the bound parameters. This inserts the document along with its vector representation into the multilingual_table.
-- A confirmation message is printed to provide feedback that the document was successfully inserted.

This approach efficiently ingests data into the database while ensuring that each document is uniquely identified and searchable via its vector embedding.

"""

# Define the CQL insert statement for adding documents to the multilingual_table.
# The columns in the INSERT statement are specified in the same order as
# the values provided.
insert_cql = """
INSERT INTO default_keyspace.multilingual_table ("_id", country, description, embedding, name)
VALUES (?, ?, ?, ?, ?)
"""

# Prepare the CQL statement using the session object.
# Preparing the statement allows the query to be compiled once and reused
# efficiently.
prepared = session.prepare(insert_cql)

# Set the write consistency level to LOCAL_QUORUM.
# LOCAL_QUORUM is a consistency level allowed by Astra DB that ensures
# writes are acknowledged by a majority of replicas in the local
# datacenter.
prepared.consistency_level = ConsistencyLevel.LOCAL_QUORUM

# Define a list of sample documents to be ingested into the table.
# Each document is a dictionary containing 'name', 'description', and
# 'country'.
documents = [
    {
        "name": "Jóhann Müller",
        "description": "Software developer from Berlin",
        "country": "Germany",
    },
    {"name": "Jean Dupont", "description": "Développeur de logiciels à Paris", "country": "France"},
    {
        "name": "Giovanni Rossi",
        "description": "Sviluppatore software di Milano",
        "country": "Italy",
    },
    {"name": "Anna Schmidt", "description": "Entwicklerin aus Berlin", "country": "Germany"},
    {
        "name": "Markus Weber",
        "description": "Senior software engineer in Berlin",
        "country": "Germany",
    },
    # Additional documents can be added as needed.
]

# Loop through each document in the sample data.
for doc in documents:
    # Generate a unique identifier (UUID) for the document.
    uid = str(uuid.uuid4())

    # Concatenate the document's name, description, and country into a single string.
    # This string is used to compute a vector embedding representing the
    # document.
    text_for_encoding = f"{doc['name']} {doc['description']} {doc['country']}"

    # Compute the vector embedding using the previously defined encode()
    # function.
    emb = encode(text_for_encoding)

    # Execute the prepared CQL insert statement with the following bound values:
    # - uid: The unique identifier for the document.
    # - doc["country"]: The country field.
    # - doc["description"]: The description field.
    # - emb: The computed vector embedding.
    # - doc["name"]: The name field.
    session.execute(prepared, (uid, doc["country"], doc["description"], emb, doc["name"]))

    # Print a confirmation message indicating successful insertion.
    print(f"Inserted document {uid} for {doc['name']}")

"""# Comprehensive Vector Search Testing with Country Filtering and Robust Query Variations

**Function Definition (search_by_vector):**

-- This function encodes the input query into a vector embedding.
-- It then constructs a CQL query that retrieves document fields and computes cosine similarity between the stored embedding and the query embedding.
-- If a country filter is provided, it adds a WHERE country = ? clause to the query.
-- The query also uses an ANN (Approximate Nearest Neighbor) clause to efficiently order the results based on similarity.
-- The function sets the consistency level to LOCAL_ONE, which is necessary for ANN queries.
--Finally, it returns all the matching rows.

**Wrapper Function (safe_search):**

-- A wrapper function that always applies a default country filter (in this case, "Germany") when performing a vector search.

-- This simplifies the API for users who always want to restrict searches by country.


**Test Cases:**

-- A list of diverse and challenging query strings (hard_test_queries) is provided to simulate real-world scenarios.

--These include queries with typos, different languages, synonyms, and creative phrasing.

--The code iterates over these queries, performs the search using safe_search, and prints out the results.

-- For each result, it prints the document's name, description, cosine similarity score (formatted to two decimals), and a computed "distance" metric (1 - similarity) for intuitive interpretation.

This code provides a comprehensive testing framework for vector search, demonstrating how to handle various input challenges and apply dynamic filtering with ANN-based similarity ranking.
"""


def search_by_vector(query_text, filter_country=None, limit=3):
    """
    Perform a vector search on the multilingual_table using ANN (Approximate Nearest Neighbor) search.
    Optionally, apply a country filter to restrict the search to documents from a specified country.

    Parameters:
    - query_text (str): The input text to be encoded into a vector.
    - filter_country (str, optional): A country name to filter results by (e.g., "Germany").
    - limit (int): Maximum number of results to return (default is 3).

    Returns:
    - list: A list of rows from the query result.
    """
    # Encode the input query text into a vector using the encode() function.
    query_emb = encode(query_text)

    if filter_country:
        # If a country filter is provided, build a CQL query that includes a
        # WHERE clause.
        cql = """
        SELECT
          "_id",
          name,
          description,
          country,
          similarity_cosine(embedding, ?) AS sim
        FROM default_keyspace.multilingual_table
        WHERE country = ?
        ORDER BY embedding ANN OF ?
        LIMIT ?
        """
        # Prepare the CQL statement.
        prepared = session.prepare(cql)
        # Set the consistency level to LOCAL_ONE (required for Top-K/ANN
        # queries).
        prepared.consistency_level = ConsistencyLevel.LOCAL_ONE
        # Execute the prepared query with bound parameters:
        # 1st: query_emb for cosine similarity computation,
        # 2nd: filter_country for the WHERE clause,
        # 3rd: query_emb again for ANN ordering,
        # 4th: limit to restrict the number of results.
        rows = session.execute(prepared, (query_emb, filter_country, query_emb, limit))
    else:
        # If no country filter is specified, build a simpler CQL query without
        # a WHERE clause.
        cql = """
        SELECT
          "_id",
          name,
          description,
          country,
          similarity_cosine(embedding, ?) AS sim
        FROM default_keyspace.multilingual_table
        ORDER BY embedding ANN OF ?
        LIMIT ?
        """
        # Prepare the statement.
        prepared = session.prepare(cql)
        prepared.consistency_level = ConsistencyLevel.LOCAL_ONE
        # Execute the query with the query vector bound twice (for similarity
        # and ANN ordering) and the limit.
        rows = session.execute(prepared, (query_emb, query_emb, limit))

    # Return all rows from the result set as a list.
    return rows.all()


# A simple wrapper that always uses a country filter (defaulting to "Germany").
def safe_search(query_text, country_filter="Germany", limit=3):
    """
    Wrapper for search_by_vector that applies a default country filter.

    Parameters:
    - query_text (str): The text query to search for.
    - country_filter (str): The country to filter by (default is "Germany").
    - limit (int): Maximum number of results to return.

    Returns:
    - list: Query result rows.
    """
    return search_by_vector(query_text, filter_country=country_filter, limit=limit)


