"""#Refreshing Schema Metadata and Implementing Hybrid Search with Advanced Filtering

**Refreshing Schema Metadata:**

Purpose:
The call to session.cluster.refresh_schema_metadata() updates the local cache of the cluster’s schema. This is important after making schema changes (e.g., adding new tables or columns) so that the driver’s view is up-to-date before executing queries.

**Hybrid Search Function (hybrid_search):**

Vector Encoding:
The function starts by encoding the input query_text into a vector (query_emb) using the encode() function. This vector is crucial for computing similarity between the query and stored document embeddings.

Base Query Definition:
The base_query selects various document fields from the enriched_multilingual_table and computes the cosine similarity between each document’s embedding and the query embedding. The similarity score is aliased as sim.

Dynamic Filter Building:
The function supports multiple types of filters:

-- Equality Filters: For straightforward field comparisons.
-- Range Filters: Using $gte (greater than or equal to) and $lte (less than or equal to) to specify bounds.
-- IN Clause Filters: Allowing for filtering against multiple values using an IN clause.
These filters are dynamically appended to the base query and corresponding parameters are added to the params list.

ANN Clause and Parameter Binding:
The ANN (Approximate Nearest Neighbor) clause orders the results based on the similarity of the vector embeddings. The query vector is bound a second time for this purpose, and the limit parameter restricts the number of results.

Query Preparation and Execution:

The complete query is prepared using session.prepare(), with the consistency level set to LOCAL_ONE for performance and reliability in Top-K/ANN queries. The prepared query is then executed with all bound parameters, and the function returns the resulting rows.

This implementation provides a flexible hybrid search that leverages both vector similarity (for semantic search) and traditional field filters, enabling complex queries on enriched data stored in Cassandra.
"""

# Refresh the schema metadata for the connected Cassandra cluster.
# This command forces the driver to update its internal schema cache,
# ensuring that any recent changes (e.g., new tables, columns, or indexes)
# are recognized and used in subsequent queries.
session.cluster.refresh_schema_metadata()


def hybrid_search(query_text, filter_dict=None, limit=5):
    """
    Hybrid search that combines vector search (using ANN ordering) with classic field filters.

    Parameters:
      - query_text: The text query to encode into a vector.
      - filter_dict: A dictionary of filters to apply. This supports:
          * Equality: {"location": "Berlin", "job_title": "Senior Software Developer"}
          * Range: {"experience": {"$gte": 5, "$lte": 10}, "salary": {"$gte": 70000, "$lte": 100000}}
          * IN clause: {"job_title": {"$in": ["Software Developer", "Developer", "Programmer", "Software Engineer"]}}
      - limit: The maximum number of results to return.

    Returns:
      - A list of rows matching the query.
    """
    # Encode the query text into its vector representation using the encode()
    # function.
    query_emb = encode(query_text)

    # Define the base CQL query to select document fields and compute cosine
    # similarity.
    base_query = """
    SELECT "_id", name, job_title, description, experience, location, salary, language,
           similarity_cosine(embedding, ?) AS sim
    FROM default_keyspace.enriched_multilingual_table
    """
    # Start the list of parameters with the query embedding, used in the
    # similarity_cosine() function.
    params = [query_emb]

    # Initialize a list to hold conditions for the WHERE clause.
    conditions = []

    # If additional filters are provided, build the appropriate conditions.
    if filter_dict:
        for col, val in filter_dict.items():
            if isinstance(val, dict):
                # Handle range filters: both lower and upper bounds.
                if "$gte" in val and "$lte" in val:
                    conditions.append(f"{col} >= ? AND {col} <= ?")
                    params.extend([val["$gte"], val["$lte"]])
                # Handle only a lower bound.
                elif "$gte" in val:
                    conditions.append(f"{col} >= ?")
                    params.append(val["$gte"])
                # Handle only an upper bound.
                elif "$lte" in val:
                    conditions.append(f"{col} <= ?")
                    params.append(val["$lte"])
                # Handle IN clause filters.
                elif "$in" in val:
                    in_vals = val["$in"]
                    # Create placeholders for each value in the IN clause.
                    placeholders = ", ".join("?" for _ in in_vals)
                    conditions.append(f"{col} IN ({placeholders})")
                    params.extend(in_vals)
            else:
                # For simple equality filters.
                conditions.append(f"{col} = ?")
                params.append(val)

    # Build the WHERE clause if any conditions were specified.
    where_clause = ""
    if conditions:
        where_clause = "WHERE " + " AND ".join(conditions)

    # Define the ANN ordering clause.
    # The query embedding is bound a second time for the ANN ordering,
    # and 'limit' restricts the number of returned rows.
    ann_clause = "ORDER BY embedding ANN OF ? LIMIT ?"
    params.extend([query_emb, limit])

    # Combine the base query, optional WHERE clause, and ANN clause into a
    # complete CQL query.
    cql_query = f"{base_query} {where_clause} {ann_clause}"

    # Debug statements (optional):
    # print("CQL Query:", cql_query)
    # print("Params:", params)

    # Prepare the query to optimize execution.
    prepared = session.prepare(cql_query)
    # Set the consistency level to LOCAL_ONE, which is required for Top-K/ANN
    # queries.
    prepared.consistency_level = ConsistencyLevel.LOCAL_ONE
    # Execute the prepared query with the collected parameters.
    rows = session.execute(prepared, tuple(params))

    # Return all matching rows as a list.
    return rows.all()


"""# Advanced Complex Vector Search with Optional Equality Filters

**Vector Encoding:**
The function starts by encoding the provided query_text into a high-dimensional vector (query_emb) using the encode() function. This vector is used to compute similarity against document embeddings.

**Base Query Construction: **
The base_query selects key fields from the enriched_multilingual_table and calculates the cosine similarity between the stored document embeddings and query_emb. The similarity score is aliased as sim.

**Dynamic WHERE Clause with Filters:**
If a filters dictionary is provided, the function builds a WHERE clause by iterating over the dictionary and appending equality conditions (e.g., "country = ?"). The corresponding filter values are added to the params list.

**ANN Clause and Parameter Binding:**
The ANN clause (ORDER BY embedding ANN OF ? LIMIT ?) is appended to order the results by similarity and limit the number of returned rows. The query_emb is bound again for ANN ordering, and the limit is appended to the parameters.

**Query Preparation and Execution:**
The complete CQL query is prepared using session.prepare(cql_query) for efficiency. The consistency level is set to LOCAL_ONE, then the query is executed with all the bound parameters, and the function returns the resulting rows.

This function integrates vector-based similarity search with conventional equality filters, enabling advanced hybrid querying on enriched data.
"""


def search_by_vector_complex(query_text, filters=None, limit=5):
    """
    Perform a vector search on the enriched_multilingual_table using ANN search with optional additional filters.

    This function encodes the query text into a vector, then constructs a CQL query that:
      - Retrieves documents along with a computed cosine similarity score.
      - Applies optional equality filters based on the provided filters dictionary.
      - Orders the results using ANN (Approximate Nearest Neighbor) search based on the embedding similarity.
      - Limits the number of results returned.

    Parameters:
      query_text (str): The text to be encoded into a vector for the search.
      filters (dict, optional): A dictionary of equality filters to apply (e.g., {"country": "Germany"}).
      limit (int): The maximum number of results to return (default is 5).

    Returns:
      list: A list of rows matching the search criteria.
    """
    # Encode the query text into a vector representation using the encode()
    # function.
    query_emb = encode(query_text)

    # Define the base part of the CQL query.
    # This selects document fields from the enriched_multilingual_table and computes the cosine similarity
    # between each document's embedding and the query vector (query_emb) using
    # the similarity_cosine function.
    base_query = """
    SELECT "_id", name, description, country, embedding,
           similarity_cosine(embedding, ?) AS sim
    FROM default_keyspace.enriched_multilingual_table
    """
    # Start the parameter list with the query embedding, which is needed for
    # the similarity_cosine() calculation.
    params = [query_emb]

    # Initialize an empty WHERE clause.
    where_clause = ""
    # If filters are provided, build the WHERE clause by adding equality
    # conditions.
    if filters:
        conditions = []
        # Iterate over each key-value pair in the filters dictionary.
        for col, val in filters.items():
            # For each filter, add an equality condition (e.g., "country = ?").
            conditions.append(f"{col} = ?")
            # Append the filter value to the parameters list.
            params.append(val)
        # Combine the conditions with 'AND' and prepend with "WHERE".
        where_clause = "WHERE " + " AND ".join(conditions)

    # Define the ANN (Approximate Nearest Neighbor) ordering clause with a LIMIT.
    # The query_emb is bound again to serve as the reference vector for ANN
    # ordering.
    ann_clause = "ORDER BY embedding ANN OF ? LIMIT ?"
    # Append the query embedding (for ANN ordering) and the limit to the
    # parameters list.
    params.extend([query_emb, limit])

    # Combine the base query, optional WHERE clause, and ANN ordering clause
    # to form the final CQL query.
    cql_query = f"{base_query} {where_clause} {ann_clause}"

    # Prepare the CQL query for execution, which compiles it for efficient
    # repeated use.
    prepared = session.prepare(cql_query)
    # Set the consistency level to LOCAL_ONE, which is required for efficient
    # Top-K/ANN queries.
    prepared.consistency_level = ConsistencyLevel.LOCAL_ONE

    # Execute the prepared query by passing in the parameters tuple.
    rows = session.execute(prepared, tuple(params))

    # Return all the resulting rows as a list.
    return rows.all()


