"""# Advanced Query Examples Using Explicit LIKE Operator and Hybrid Search

**Hybrid Search Function:**

Purpose:
The hybrid_search function combines vector search (via ANN ordering) with traditional field filters. It encodes a text query into a vector and builds a dynamic CQL query to retrieve documents from the enriched_multilingual_table.


**Parameters:**

query_text: The text query that is vectorized.
filter_dict: A dictionary that may contain equality, range (using $gte, $lte), or IN clause filters.
limit: Maximum number of results to return.

**Query Construction:**
Base Query: Selects various fields and computes cosine similarity with the embedding.
Dynamic WHERE Clause: If filters are provided, conditions are built and added to the query.
ANN Clause: Orders the results based on vector similarity using the ORDER BY embedding ANN OF ? LIMIT ? clause.

**Execution:**
The complete query is prepared and executed with the collected parameters. The function returns all matching rows.
Alias:

safe_search_dse is simply an alias for hybrid_search, making it more convenient to refer to the function in later examples.
Functions for Explicit LIKE Operator Filtering:

**build_regex_pattern:**

Converts a wildcard pattern (using '*' or '%') into a regex pattern. It replaces wildcards with .* after escaping other special characters.

parse_explicit_like: **texte en gras**
Parses a query string formatted as "field LIKE 'pattern'" and extracts the field and converts the pattern to a regex using build_regex_pattern.
Advanced Query Examples Using Explicit LIKE Operator:

**Explicit LIKE Query Example:**
A sample explicit LIKE query ("job_title LIKE '%Developer%'") is parsed to extract the field (job_title) and convert the pattern to a regex.
A hybrid search is then executed using safe_search_dse with a basic filter (location "Berlin").
After obtaining the results, client-side regex filtering is applied on the extracted field to further narrow down the results.

Output:
The first three results that match the regex pattern are printed, displaying the candidate's name, job title, and cosine similarity score.

This comprehensive code snippet demonstrates how to integrate traditional field filters, vector search, and explicit LIKE filtering using regex, providing advanced capabilities for hybrid search scenarios in a Cassandra-based environment.







"""


# ---- Hybrid Search Function----
def hybrid_search(query_text, filter_dict=None, limit=5):
    """
    Hybrid search that combines vector (ANN) search with classic field filters.

    Parameters:
      - query_text: The text query to encode.
      - filter_dict: Dictionary of filters (supports equality, range, and IN clauses).
      - limit: Maximum number of results.

    Returns:
      List of matching rows.
    """
    # Encode the query text into a vector representation.
    query_emb = encode(query_text)

    # Define the base CQL query that selects key fields from the enriched_multilingual_table,
    # and computes cosine similarity between the document embedding and
    # query_emb.
    base_query = """
    SELECT "_id", name, job_title, description, experience, location, salary, language,
           similarity_cosine(embedding, ?) AS sim
    FROM default_keyspace.enriched_multilingual_table
    """
    # Start the parameters list with the query embedding needed for the
    # similarity function.
    params = [query_emb]

    # Prepare a list to hold conditions for the WHERE clause based on provided
    # filters.
    conditions = []
    if filter_dict:
        for col, val in filter_dict.items():
            if isinstance(val, dict):
                # For range filters: both lower and upper bounds.
                if "$gte" in val and "$lte" in val:
                    conditions.append(f"{col} >= ? AND {col} <= ?")
                    params.extend([val["$gte"], val["$lte"]])
                # For lower bound only.
                elif "$gte" in val:
                    conditions.append(f"{col} >= ?")
                    params.append(val["$gte"])
                # For upper bound only.
                elif "$lte" in val:
                    conditions.append(f"{col} <= ?")
                    params.append(val["$lte"])
                # For IN clause filters.
                elif "$in" in val:
                    in_vals = val["$in"]
                    placeholders = ", ".join("?" for _ in in_vals)
                    conditions.append(f"{col} IN ({placeholders})")
                    params.extend(in_vals)
            else:
                # For simple equality filters.
                conditions.append(f"{col} = ?")
                params.append(val)
    # Build the WHERE clause if any conditions exist.
    where_clause = "WHERE " + " AND ".join(conditions) if conditions else ""

    # Define the ANN clause for ordering by vector similarity.
    # Bind query_emb again for the ANN ordering, and apply the result limit.
    ann_clause = "ORDER BY embedding ANN OF ? LIMIT ?"
    params.extend([query_emb, limit])

    # Combine the base query, WHERE clause, and ANN clause into a complete CQL
    # query.
    cql_query = f"{base_query} {where_clause} {ann_clause}"
    # Debug prints can be enabled if needed:
    # print("CQL Query:", cql_query)
    # print("Params:", params)

    # Prepare the query for efficient execution.
    prepared = session.prepare(cql_query)
    prepared.consistency_level = ConsistencyLevel.LOCAL_ONE
    # Execute the prepared query with the collected parameters.
    rows = session.execute(prepared, tuple(params))
    return rows.all()


# For convenience, alias safe_search_dse to hybrid_search.
safe_search_dse = hybrid_search


# ---- Functions for Explicit LIKE Operator Filtering ----
def build_regex_pattern(query_pattern):
    """
    Converts a query pattern containing '*' or '%' wildcards into a valid regex pattern.

    The function replaces wildcards with '.*' (regex syntax for any character sequence)
    after escaping all other regex special characters.
    """
    # Use a placeholder that is unlikely to appear in the text.
    placeholder = "__WILDCARD__"
    # Replace '*' and '%' with the placeholder.
    temp_pattern = query_pattern.replace("*", placeholder).replace("%", placeholder)
    # Escape all regex special characters in the string.
    escaped = re.escape(temp_pattern)
    # Replace the placeholder with '.*' to allow any character sequence.
    regex_pattern = escaped.replace(placeholder, ".*")
    print(f"DEBUG: Converted '{query_pattern}' to regex pattern '{regex_pattern}'")
    return regex_pattern


def parse_explicit_like(query):
    """
    Parses a query like "field LIKE 'pattern'" and returns a tuple (field, regex_pattern).

    It uses regular expressions to extract the field and pattern,
    then converts the pattern into a valid regex pattern using build_regex_pattern().
    """
    pattern = r"(\w+)\s+LIKE\s+'(.+)'"
    match = re.search(pattern, query, re.IGNORECASE)
    if match:
        field = match.group(1)
        like_pattern = match.group(2)
        regex = build_regex_pattern(like_pattern)
        return field, regex
    return None, None


# ---- Advanced Query Examples Using Explicit LIKE Operator ----
print("=== Advanced Query Examples Using Explicit LIKE Operator ===\n")

# Example: Explicit LIKE Query
