print(f"Found {len(filtered_results)} documents matching the pattern")

# Print the matching documents in a nice format
print("\nMatching Documents:")
print("=" * 80)
for i, row in enumerate(filtered_results, 1):
    print(f"{i}. Name: {row.name}")
    print(f"   Job Title: {row.job_title}")
