"""#Advanced Query Examples Using Explicit LIKE Operator

**Header and Import:**

The script starts by printing a header indicating that advanced query examples using the explicit LIKE operator are being demonstrated.
The re module is imported for regex operations.

**Function build_regex_pattern:**

Purpose: Converts wildcard patterns (using * or %) into regex patterns.
Process:
Replaces wildcards with a placeholder string.
Escapes the entire string to neutralize any regex-special characters.
Replaces the placeholder with .* to allow matching any sequence of characters.
Debug Output:
Prints the escaped pattern and the final regex pattern for verification.

**Function parse_explicit_like:**

Purpose: Parses a query string containing the SQL-like syntax (e.g., "job_title LIKE '%Developer%'").
Process:
Uses a regex to capture the field name and the LIKE pattern from the input query.
Calls build_regex_pattern to convert the LIKE pattern to a regex.
Returns the extracted field and the regex pattern.

**Explicit LIKE Query Example:**

An example query ("job_title LIKE '%Developer%'") is parsed.
The parsed field and regex pattern are printed.
Retrieving Candidate Documents:

Uses the safe_search_dse function (an alias for hybrid_search) to retrieve candidate rows from the enriched table.
The search is filtered to documents where the location is "Berlin" and based on the vector query "Software Developer".
The resulting rows are converted to a list.

**Client-Side Regex Filtering:**

The parsed field and regex pattern from the explicit LIKE query are used to filter the candidate rows on the client side.
For each row, the attribute corresponding to the parsed field is checked against the regex pattern.
Only rows matching the regex are retained.

**Displaying Results:**

The script prints the first three filtered results, showing the candidate's name, job title, and cosine similarity score (formatted to two decimal places).

This code snippet demonstrates how to enhance hybrid search with explicit LIKE filtering by converting SQL-like patterns to regex and applying additional client-side filtering on the search results.
"""

print("=== Advanced Query Examples Using Explicit LIKE Operator ===\n")


# -------------------------------------------------------------------------------
# Function: build_regex_pattern
# -------------------------------------------------------------------------------
# Purpose:
#   This function converts a query pattern containing '*' or '%' wildcards into a regex pattern.
#   It escapes the entire pattern to neutralize regex-special characters and then replaces
#   the escaped wildcards with '.*' to simulate SQL LIKE matching.
def build_regex_pattern(query_pattern):
    # Use a placeholder for wildcards.
    placeholder = "__WILDCARD__"
    # Replace '*' and '%' with the placeholder.
    temp_pattern = query_pattern.replace("*", placeholder).replace("%", placeholder)
    # Escape the pattern to neutralize regex-special characters.
    escaped = re.escape(temp_pattern)
    # Replace the placeholder with '.*' which in regex means "match any
    # characters".
    regex_pattern = escaped.replace(placeholder, ".*")
    print(f"DEBUG: Escaped pattern for '{query_pattern}' is '{escaped}'")
    print(f"DEBUG: Regex pattern after conversion is '{regex_pattern}'")
    return regex_pattern


# -------------------------------------------------------------------------------
# Function: parse_explicit_like
# -------------------------------------------------------------------------------
# Purpose:
#   This function parses a query using the explicit LIKE operator.
#   For example, "job_title LIKE '%Developer%'" extracts the field "job_title" and the pattern "%Developer%"
#   and converts the pattern into a regex pattern.
def parse_explicit_like(query):
    # Define a regex pattern to capture a field name, the LIKE keyword, and a
    # pattern enclosed in single quotes.
    pattern = r"(\w+)\s+LIKE\s+'(.+)'"
    match = re.search(pattern, query, re.IGNORECASE)
    if match:
        # Extract the field name.
        field = match.group(1)
        # Extract the LIKE pattern.
        like_pattern = match.group(2)
        # Convert the LIKE pattern into a regex pattern.
        regex = build_regex_pattern(like_pattern)
        return field, regex
    return None, None


# -------------------------------------------------------------------------------
# Example: Explicit LIKE Operator Query
# -------------------------------------------------------------------------------
explicit_like_query = "job_title LIKE '%Developer%'"
# Parse the explicit LIKE query to extract the field and convert the pattern.
field, regex_pattern = parse_explicit_like(explicit_like_query)
print(f"\nExplicit LIKE Query: '{explicit_like_query}'")
print(f"Parsed Field: '{field}', Regex Pattern: '{regex_pattern}'")

# -------------------------------------------------------------------------------
# Retrieve Candidate Documents from Cassandra using Hybrid Search
# -------------------------------------------------------------------------------
# Here, we use our safe_search_dse function (alias for hybrid_search) to get candidate rows
# from the enriched_multilingual_table.
# We apply a basic filter on location ("Berlin") and sort the results by vector similarity
# using a reference query "Software Developer".
results_like = safe_search_dse("Software Developer", filter_dict={"location": "Berlin"}, limit=10)
results_like = list(results_like)

# -------------------------------------------------------------------------------
# Apply Client-Side Regex Filtering Based on the Explicit LIKE Query
# -------------------------------------------------------------------------------
# Use the parsed field and regex pattern to filter candidate rows on the
# client side.
if field and regex_pattern:
    # For each row, get the attribute corresponding to the parsed field and
    # test it against the regex.
    filtered_results_like = [
        row
        for row in results_like
        if re.search(regex_pattern, getattr(row, field, ""), re.IGNORECASE)
    ]
else:
    filtered_results_like = results_like

# -------------------------------------------------------------------------------
# Display the Filtered Results
# -------------------------------------------------------------------------------
print("\nResults for Explicit LIKE Query after client-side regex filtering:")
# Print up to the first 3 filtered results.
for row in filtered_results_like[:3]:
    print(f"  - {row.name} | {row.job_title} | (Cosine Similarity: {row.sim:.2f})")
